&lt;h4 style=&quot;text-align: center;&quot;&gt;&lt;img style=&quot;max-width: 100%;&quot; src=&quot;https://info.rfsmart.com/hubfs/EVP/EVP%20statement.png&quot; alt=&quot;&quot; width=&quot;640&quot;&gt;&lt;/h4&gt;
&lt;h3 style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-size: 18.6667px;&quot;&gt;NetSuite Architect&lt;/span&gt;&lt;/h3&gt;
